import React, { useRef, useState } from 'react';

interface TiltContainerProps {
  children: React.ReactNode;
  className?: string;
  intensity?: number;
}

export const TiltContainer: React.FC<TiltContainerProps> = ({ children, className = '', intensity = 15 }) => {
  const ref = useRef<HTMLDivElement>(null);
  const [transform, setTransform] = useState('');
  const [glow, setGlow] = useState({ x: 50, y: 50, opacity: 0 });

  const handleMouseMove = (e: React.MouseEvent<HTMLDivElement>) => {
    if (!ref.current) return;
    const { left, top, width, height } = ref.current.getBoundingClientRect();
    const x = e.clientX - left;
    const y = e.clientY - top;

    // Calculate percentage for tilt
    const xPct = x / width;
    const yPct = y / height;

    const tiltX = (yPct - 0.5) * intensity * -1; // Invert for natural feel
    const tiltY = (xPct - 0.5) * intensity; 

    setTransform(`perspective(1000px) rotateX(${tiltX}deg) rotateY(${tiltY}deg) scale(1.02)`);
    setGlow({ x: xPct * 100, y: yPct * 100, opacity: 1 });
  };

  const handleMouseLeave = () => {
    setTransform('perspective(1000px) rotateX(0deg) rotateY(0deg) scale(1)');
    setGlow((prev) => ({ ...prev, opacity: 0 }));
  };

  return (
    <div
      ref={ref}
      className={`transition-transform duration-200 ease-out transform-gpu ${className}`}
      onMouseMove={handleMouseMove}
      onMouseLeave={handleMouseLeave}
      style={{ transform, transformStyle: 'preserve-3d' }}
    >
      {/* Dynamic Glow Gradient */}
      <div 
        className="absolute inset-0 z-0 pointer-events-none transition-opacity duration-500 rounded-3xl"
        style={{
          background: `radial-gradient(circle at ${glow.x}% ${glow.y}%, rgba(255, 255, 255, 0.1), transparent 50%)`,
          opacity: glow.opacity,
        }}
      />
      <div className="relative z-10 h-full">
        {children}
      </div>
    </div>
  );
};

import React, { useRef, useMemo } from 'react';
import { Canvas, useFrame, useThree } from '@react-three/fiber';
import * as THREE from 'three';

const ParticleField = () => {
  const count = 2000;
  const mesh = useRef<THREE.Points>(null!);
  const { mouse } = useThree();

  const particlesPosition = useMemo(() => {
    const positions = new Float32Array(count * 3);
    for (let i = 0; i < count; i++) {
      positions[i * 3] = (Math.random() - 0.5) * 20; // x
      positions[i * 3 + 1] = (Math.random() - 0.5) * 20; // y
      positions[i * 3 + 2] = (Math.random() - 0.5) * 20; // z
    }
    return positions;
  }, []);

  useFrame((state) => {
    const time = state.clock.getElapsedTime();
    if (mesh.current) {
      // Rotate constantly
      mesh.current.rotation.y = time * 0.05;

      // React to mouse
      // Interpolate rotation based on mouse position for fluid movement
      const targetRotationX = mouse.y * 0.2;
      const targetRotationY = mouse.x * 0.2;

      mesh.current.rotation.x = THREE.MathUtils.lerp(mesh.current.rotation.x, targetRotationX + (time * 0.02), 0.1);
      mesh.current.rotation.y = THREE.MathUtils.lerp(mesh.current.rotation.y, targetRotationY + (time * 0.05), 0.1);
    }
  });

  return (
    <points ref={mesh}>
      <bufferGeometry>
        <bufferAttribute
          attach="attributes-position"
          count={particlesPosition.length / 3}
          array={particlesPosition}
          itemSize={3}
        />
      </bufferGeometry>
      <pointsMaterial
        size={0.03}
        color="#00f0ff"
        transparent
        opacity={0.6}
        sizeAttenuation
        depthWrite={false}
      />
    </points>
  );
};

