import { ScrollTrigger } from 'gsap/ScrollTrigger';

const screens = [
  "Shield Dashboard", "Intent Configuration", "Filter Logic Nodes", "Pulse Feed (News)", 
  "Lens (Visuals)", "User Profile", "Safety Analytics", "Notification Center"
];

export const Gallery: React.FC = () => {
  const containerRef = useRef<HTMLDivElement>(null);
  const sliderRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const ctx = gsap.context(() => {
      const totalWidth = sliderRef.current ? sliderRef.current.scrollWidth - window.innerWidth : 0;

      gsap.to(sliderRef.current, {
        x: -totalWidth,
        ease: "none",
        scrollTrigger: {
          trigger: containerRef.current,
          pin: true,
          scrub: 1,
          end: () => "+=" + sliderRef.current!.scrollWidth,
        }
      });
    }, containerRef);
    return () => ctx.revert();
  }, []);

  return (
    <section ref={containerRef} className="w-full h-screen overflow-hidden flex flex-col justify-center relative bg-[#0D0D0D]">
      <div className="absolute top-12 left-8 md:left-20 z-20">
        <h2 className="text-3xl md:text-5xl font-bold text-white mb-2">Artifacts</h2>
        <p className="text-indigo-400 font-mono text-sm tracking-widest">20 UI SCREENS &bull; 6 UX FRAMES</p>
      </div>

      <div ref={sliderRef} className="flex gap-8 px-8 md:px-20 items-center h-[60vh] md:h-[70vh]">
        {screens.map((title, index) => (
          <div 
            key={index} 
            className="flex-shrink-0 w-[300px] md:w-[450px] h-[500px] md:h-[650px] glass-panel rounded-lg border border-white/10 flex flex-col items-center justify-center relative group hover:border-indigo-500/40 transition-all duration-500"
          >
            <div className="absolute inset-0 bg-gradient-to-b from-transparent to-black/90 z-10 rounded-lg"></div>
            {/* Placeholder for actual UI image */}
            <div className="w-full h-full bg-[#111] rounded-lg overflow-hidden relative grayscale group-hover:grayscale-0 transition-all duration-700">
               <img 
                src={`https://picsum.photos/450/650?random=${index + 20}`} 
                alt={title} 
                className="w-full h-full object-cover opacity-50 group-hover:opacity-80 transition-opacity transform group-hover:scale-105 duration-1000"
              />
            </div>
            <div className="absolute bottom-10 left-8 z-20">
              <span className="text-indigo-400 text-[10px] font-mono mb-2 block tracking-widest">FIGMA PROTOTYPE 0{index + 1}</span>
              <h3 className="text-xl font-bold text-white">{title}</h3>
            </div>
          </div>
        ))}
        {/* End Spacer */}
        <div className="w-[20vw]"></div>
      </div>
    </section>
  );
};

